B.CONTRACT_NUM CONTRACT_NUM, B.BAN AS CUSTOMER_BAN, A.SOC, AD_SSN, (SELECT RATE_NM SERVICE_NM FROM MSP_RATE_MST WHERE RATE_CD = SOC and rownum = 1)AS SERVICE_NM, A.SERVICE_TYPE, F_GET_KT_CODE_NM('PPS_CUSTOMER','SERVICE_TYPE',A.SERVICE_TYPE) SERVICE_TYPE_NM, PAPER_IMAGE_1, PAPER_IMAGE_2, PAPER_IMAGE_3, PAPER_IMAGE_4, PAPER_IMAGE_5, NVL(D.PAPER_IMAGE, 0) PAPER_IMAGE, NVL(AGENT_ID, '') AGENT_ID, F_GET_AGENT_NM(AGENT_ID) AGENT_NM, VIR_ACCOUNT_ID, BASIC_REMAINS, TO_CHAR(BASIC_EXPIRE, 'YYYY-MM-DD') BASIC_EXPIRE, TO_CHAR(BASIC_EMPT_DT, 'YYYY-MM-DD') BASIC_EMPT_DT, TO_CHAR(A.ENTER_DATE, 'YYYY-MM-DD HH24:MI:SS') ENTER_DATE, NVL(LANG_CODE, '') LANG_CODE, NVL(AD_NATION,'') AD_NATION, DECODE(AD_NATION,'','미등록', F_GET_KT_CODE_NM('PPS_CUSTOMER', 'AD_NATION', AD_NATION)) AD_NATION_NM, B.CUSTOMER_ID, B.SUBSCRIBER_NO, B.SUB_STATUS, F_GET_KT_CODE_NM('PPS_CUSTOMER','SUB_STATUS',B.SUB_STATUS) SUB_STATUS_NM, USER_SSN, B.SUB_LINK_NAME AS SUB_LINK_NAME, B.MODEL_NAME AS MODEL_NAME, B.MODEL_ID AS MODEL_ID, B.BAN AS BAN, B.LST_COM_ACTV_DATE AS LST_COM_ACTV_DATE, A.CMS_CHARGE_TYPE AS CMS_CHARGE_TYPE, NVL(A.AGENT_SALE_ID,'') AGENT_SALE_ID , F_GET_AGENT_NM(AGENT_SALE_ID) AGENT_SALE_NM, SO_CD, F_GET_KT_CODE_NM('PPS_CUSTOMER','SO_CD', SO_CD) SO_CD_NM, MNP_IND_CD, DECODE(MNP_IND_CD, '', '신규', '이동') MNP_IND_CD_NM, VIZA_FLAG, CUST_IDNT_NO_IND_CD, F_GET_KT_CODE_NM('MSP_JUO_CUS_INFO','CUST_IDNT_NO_IND_CD',CUST_IDNT_NO_IND_CD) CUST_IDNT_NO_IND_CD_NM, RECHARGE_FLAG, TO_CHAR(STAY_EXPIR_DT, 'YYYY-MM-DD') STAY_EXPIR_DT, DECODE (NVL(B.SRL_IF_ID,''),0,'OFF','','OFF','ON') AS SRL_IF_ID_NM FROM PPS_CUSTOMER A, MSP_JUO_SUB_INFO B, (SELECT A.CONTRACT_NUM CONTRACT_NUM, CSTMR_TYPE, B.APP_INST_YN APP_INST_YN, A.NW_BLCK_AGRM_YN NW_BLCK_AGRM_YN, A.APP_BLCK_AGRM_YN APP_BLCK_AGRM_YN FROM MSP_REQUEST A, MSP_REQUEST_AGENT B WHERE A.REQUEST_KEY = B.REQUEST_KEY AND A.CSTMR_TYPE = 'NM') C, (SELECT COUNT(*) PAPER_IMAGE, CONTRACT_NUM FROM PPS_CUSTOMER_IMAGE WHERE STATUS <> 'D' GROUP BY CONTRACT_NUM) D, MSP_RATE_MST E, MSP_JUO_CUS_INFO F WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.CONTRACT_NUM = C.CONTRACT_NUM(+) AND A.CONTRACT_NUM = D.CONTRACT_NUM(+) AND A.SOC = E.RATE_CD AND B.SUB_STATUS IN ('A', 'S') AND B.CUSTOMER_ID = F.CUSTOMER_ID AND ENTER_DATE > TO_DATE('1900-01-01','YYYY-MM-DD') AND E.PAY_CL_CD = 'PP'
AND B.CONTRACT_NUM = (select F_GET_LIKE_CTN2_CONTRACT_NUM(#{searchNm}) from dual)
AND A.CONTRACT_NUM = #{searchNm}
AND B.CUSTOMER_ID = #{searchNm}
AND B.BAN = #{searchNm}
AND B.SUB_LINK_NAME LIKE '%' || #{searchNm} || '%'
AND USER_SSN = CRYPTO_AES256.ENC_AES(#{searchNm})
AND VIR_ACCOUNT_ID = #{searchNm}
AND ENTER_DATE >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
AND ENTER_DATE < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND AGENT_ID = #{searchAgentId}
AND BASIC_REMAINS >= #{searchStartRemains}
AND BASIC_REMAINS <= #{searchEndRemains}
AND A.SERVICE_TYPE = #{searchServiceType}
AND A.SOC = #{searchFeatures}
AND B.SUB_STATUS = #{searchSubStatus}
AND A.AGNT_DP_RCG_FLAG = 'Y' AND AGNT_DP_RCG_CNT IS NOT NULL AND AGNT_DP_RCG_NOW_CNT IS NOT NULL AND AGNT_DP_RCG_CNT = AGNT_DP_RCG_NOW_CNT
AND (A.AGNT_DP_RCG_FLAG = #{searchDpRcgType})
AND (A.AGNT_DP_RCG_FLAG = #{searchDpRcgType} OR A.AGNT_DP_RCG_FLAG IS NULL)
AND CMS_CHARGE_TYPE IN ('1','2')
AND CMS_CHARGE_TYPE IN ('N','0')
AND (A.AGENT_SALE_ID LIKE '%' || #{searchAgentSale} || '%' OR AGENT_SALE_ID IN (SELECT ORGN_ID FROM ORG_ORGN_INFO_MST WHERE ORGN_LVL_CD = '20' AND ORGN_NM LIKE '%' || #{searchAgentSale} || '%'))
AND VIR_ACCOUNT_ID IS NOT NULL
AND VIR_ACCOUNT_ID IS NULL
AND D.CONTRACT_NUM IS NOT NULL
AND D.CONTRACT_NUM IS NULL
AND C.CSTMR_TYPE = 'NM'
AND C.APP_BLCK_AGRM_YN = 'Y'
AND C.APP_INST_YN = 'Y'
AND B.MNP_IND_CD IS NULL
AND B.MNP_IND_CD = '1'
AND (A.VIZA_FLAG IS NULL OR A.VIZA_FLAG = 'N')
AND A.VIZA_FLAG = 'Y'
AND (A.RECHARGE_FLAG IS NULL OR A.RECHARGE_FLAG = 'N')
AND A.RECHARGE_FLAG = 'Y'

