NO_IND_CD_NM, NVL(RECHARGE_FLAG, 'N') RECHARGE_FLAG, NVL(TO_CHAR(STAY_EXPIR_DT, 'YYYY-MM-DD'),'-') STAY_EXPIR_DT, DECODE (NVL(B.SRL_IF_ID,''),0,'OFF','','OFF','ON') AS SRL_IF_ID_NM FROM PPS_CUSTOMER A, MSP_JUO_SUB_INFO B, (SELECT A.CONTRACT_NUM CONTRACT_NUM, CSTMR_TYPE, B.APP_INST_YN APP_INST_YN, A.NW_BLCK_AGRM_YN NW_BLCK_AGRM_YN, A.APP_BLCK_AGRM_YN APP_BLCK_AGRM_YN FROM MSP_REQUEST A, MSP_REQUEST_AGENT B WHERE A.REQUEST_KEY = B.REQUEST_KEY AND A.CSTMR_TYPE = 'NM') C, (SELECT COUNT(*) PAPER_IMAGE, CONTRACT_NUM FROM PPS_CUSTOMER_IMAGE WHERE STATUS <> 'D' GROUP BY CONTRACT_NUM) D, MSP_RATE_MST E, MSP_JUO_CUS_INFO F WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.CONTRACT_NUM = C.CONTRACT_NUM(+) AND A.CONTRACT_NUM = D.CONTRACT_NUM(+) AND A.SOC = E.RATE_CD AND B.SUB_STATUS IN ('A', 'S') AND B.CUSTOMER_ID = F.CUSTOMER_ID AND ENTER_DATE > TO_DATE('1900-01-01','YYYY-MM-DD') AND E.PAY_CL_CD = 'PP'
