/*+ INDEX_DESC(A PPS_CUSTOMER_IDX1) ORDERED USE_NL(A B C D) */
B.CONTRACT_NUM CONTRACT_NUM, A.SOC SOC, B.ICC_ID, (SELECT RATE_NM SERVICE_NM FROM MSP_RATE_MST WHERE RATE_CD = SOC and rownum = 1) SERVICE_NM, A.SERVICE_TYPE, F_GET_KT_CODE_NM('PPS_CUSTOMER','SERVICE_TYPE',A.SERVICE_TYPE) SERVICE_TYPE_NM, AGENT_ID, FN_GET_ORGNM(AGENT_ID) AGENT_NM, BASIC_REMAINS, TO_CHAR(BASIC_EXPIRE, 'YYYY-MM-DD') BASIC_EXPIRE, AD_NATION, AD_NAME, DECODE(AD_NATION,'','미등록', F_GET_KT_CODE_NM('PPS_CUSTOMER', 'AD_NATION', AD_NATION)) AD_NATION_NM, B.SUBSCRIBER_NO, B.SUB_STATUS, F_GET_KT_CODE_NM('PPS_CUSTOMER','SUB_STATUS',B.SUB_STATUS) SUB_STATUS_NM, USER_SSN, B.SUB_LINK_NAME AS SUB_LINK_NAME, B.MODEL_ID AS MODEL_ID, DEALER_CODE, FN_GET_CODENM('RCP0060', FN_GET_CANRSN(A.CONTRACT_NUM)) CANCEL_RSN_CODE_NM, TO_CHAR(STATUS_CANCEL_DT, 'YYYY-MM-DD HH24:MI:SS') STATUS_CANCEL_DT, TO_CHAR(STATUS_STOP_DT, 'YYYY-MM-DD') STATUS_STOP_DT, SUBSTR(B.LST_COM_ACTV_DATE, 1, 4) || '-' || SUBSTR(B.LST_COM_ACTV_DATE, 5, 2) || '-' || SUBSTR(B.LST_COM_ACTV_DATE, 7, 2) AS LST_COM_ACTV_DATE, NVL(D.PAPER_IMAGE, 0) PAPER_IMAGE, TRUNC(US_LC_VOICE/60) US_LC_VOICE, US_LC_SMS, RTRIM(TO_CHAR(NVL(US_LC_DATA, 0)/1024/1024, 'FM9999999999999990D99'), '.') US_LC_DATA, TOTAL_BASIC_CHG FROM PPS_CUSTOMER A, MSP_JUO_SUB_INFO B, MSP_RATE_MST C, (SELECT COUNT(*) PAPER_IMAGE, CONTRACT_NUM FROM PPS_CUSTOMER_IMAGE WHERE STATUS <> 'D' GROUP BY CONTRACT_NUM) D WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.SOC = C.RATE_CD AND A.CONTRACT_NUM = D.CONTRACT_NUM(+) AND SUB_STATUS = 'C' AND ENTER_DATE > TO_DATE('2000-01-01','YYYY-MM-DD') AND C.PAY_CL_CD = 'PP'
AND B.CONTRACT_NUM = #{searchNm}
