SELECT /*+ PARALLEL(4) USE_HASH(B) INDEX(A PPS_CDR_PP_IDX1) */ CALL_GUBUN, F_GET_KT_CODE_NM('PPS_CDR_PP','CALL_GUBUN',CALL_GUBUN) CALL_GUBUN_NM, NVL(CONTRACT_NUM,'') CONTRACT_NUM, CALLED_NUM, TO_CHAR(START_TIME, 'YYYY-MM-DD HH24:MI:SS') START_TIME, TO_CHAR(END_TIME, 'YYYY-MM-DD') END_TIME, USED_TIME, CHARGE, AGENT_ID, FN_GET_ORGNM(AGENT_ID) AGENT_NM, REMAINS, DATA_REMAINS, TO_CHAR(DATA_EXPIRE, 'YYYY-MM-DD') DATA_EXPIRE, TELCO_PX, TO_CHAR(A.RECORD_DATE, 'YYYY-MM-DD') RECORD_DATE, B.PREFIX PREFIX, B.KOR_NAME KOR_NAME FROM PPS_CDR_PP A, PPS_CODE_PREFIX B WHERE A.PREFIX = B.PREFIX(+)
