SELECT T.CONTRACT_NUM AS CONTRACT_NUM, T.SOC AS SOC, T.AD_SSN AS AD_SSN, T.SERVICE_NM AS SERVICE_NM, T.AGENT_ID AS AGENT_ID, T.AGENT_NM AS AGENT_NM, T.BASIC_REMAINS AS BASIC_REMAINS, T.BASIC_EXPIRE AS BASIC_EXPIRE, T.BASIC_EMPT_DT AS BASIC_EMPT_DT, T.ENTER_DATE AS ENTER_DATE, T.STATUS_STOP_DT AS STATUS_STOP_DT, T.SUB_STATUS AS SUB_STATUS, T.SUB_STATUS_NM AS SUB_STATUS_NM, T.SUB_LINK_NAME AS SUB_LINK_NAME, T.LST_COM_ACTV_DATE AS LST_COM_ACTV_DATE, T.AGENT_SALE_ID AS AGENT_SALE_ID , T.AGENT_SALE_NM AS AGENT_SALE_NM, T.MNP_IND_CD AS MNP_IND_CD, T.MNP_IND_CD_NM AS MNP_IND_CD_NM, T.TOTAL_BASIC_CHG AS TOTAL_BASIC_CHG, T.PPS35_REUSE_DATE AS PPS35_REUSE_DATE, T.AD_NATION AS AD_NATION, T.AD_NATION_NM AS AD_NATION_NM, T.BASIC_EMPT_CNT AS BASIC_EMPT_CNT, T.USE_TERM AS USE_TERM FROM ( SELECT
/*+ INDEX_DESC(A PPS_CUSTOMER_IDX1) ORDERED USE_NL(A B) */
/*+ INDEX_DESC(A PPS_CUSTOMER_IDX1) ORDERED USE_NL(A B) */
B.CONTRACT_NUM CONTRACT_NUM, A.SOC, AD_SSN, (SELECT RATE_NM SERVICE_NM FROM MSP_RATE_MST WHERE RATE_CD = SOC and rownum = 1)AS SERVICE_NM, NVL(AGENT_ID, '') AGENT_ID, F_GET_AGENT_NM(AGENT_ID) AGENT_NM, BASIC_REMAINS, TO_CHAR(BASIC_EXPIRE, 'YYYY-MM-DD') BASIC_EXPIRE, TO_CHAR(BASIC_EMPT_DT, 'YYYY-MM-DD') BASIC_EMPT_DT, TO_CHAR(A.ENTER_DATE, 'YYYY-MM-DD HH24:MI:SS') ENTER_DATE, TO_CHAR(STATUS_STOP_DT, 'YYYY-MM-DD') STATUS_STOP_DT, B.SUB_STATUS, F_GET_KT_CODE_NM('PPS_CUSTOMER','SUB_STATUS',B.SUB_STATUS) SUB_STATUS_NM, B.SUB_LINK_NAME AS SUB_LINK_NAME, B.LST_COM_ACTV_DATE AS LST_COM_ACTV_DATE, NVL(A.AGENT_SALE_ID,'') AGENT_SALE_ID , F_GET_AGENT_NM(AGENT_SALE_ID) AGENT_SALE_NM, MNP_IND_CD, DECODE(MNP_IND_CD, '', '신규', '이동') MNP_IND_CD_NM, A.TOTAL_BASIC_CHG, DECODE(SUBSTR(LST_COM_ACTV_DATE, 7, 2), '29', '28', '30', '28', '31', '28', SUBSTR(LST_COM_ACTV_DATE, 7, 2)) AS PPS35_REUSE_DATE, NVL(AD_NATION,'') AS AD_NATION, DECODE(AD_NATION,'','미등록', F_GET_KT_CODE_NM('PPS_CUSTOMER', 'AD_NATION', AD_NATION)) AS AD_NATION_NM, CASE WHEN BASIC_EMPT_DT > LAST_BASIC_CHG_DT THEN TRUNC(SYSDATE) - TRUNC(BASIC_EMPT_DT) ELSE NULL END AS BASIC_EMPT_CNT, TO_NUMBER(DECODE(B.SUB_STATUS,'A', CEIL(SYSDATE - TO_DATE(B.LST_COM_ACTV_DATE, 'YYYY-MM-DD')),'S', CEIL(A.STATUS_STOP_DT - TO_DATE(B.LST_COM_ACTV_DATE, 'YYYY-MM-DD')),'C', CEIL(A.STATUS_CANCEL_DT - TO_DATE(B.LST_COM_ACTV_DATE, 'YYYY-MM-DD')), '')) AS USE_TERM FROM PPS_CUSTOMER A, MSP_JUO_SUB_INFO B WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND ENTER_DATE > TO_DATE('1900-01-01','YYYY-MM-DD') AND B.SUB_STATUS IN ('A','S') AND A.SOC IN (SELECT SOC FROM PPS_CODE_SERVICE_TOPUP WHERE KT_MODE <> 'TOPUP_REFILL' )
AND B.CONTRACT_NUM = (select F_GET_LIKE_CTN2_CONTRACT_NUM(#{searchNm}) from dual)
AND B.CONTRACT_NUM = #{searchNm}
AND B.SUB_LINK_NAME LIKE '%' || #{searchNm} || '%'
AND A.ENTER_DATE >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
AND A.ENTER_DATE < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND BASIC_EMPT_DT >= TO_DATE(#{startEmptDt}, 'YYYY-MM-DD')
AND BASIC_EMPT_DT < TO_DATE(#{endEmptDt}, 'YYYY-MM-DD')+1
AND A.SOC = #{searchFeatures}
AND B.SUB_STATUS = #{searchSubStatus}
AND NVL(TO_NUMBER(BASIC_REMAINS),0) = 0
AND NVL(TO_NUMBER(BASIC_REMAINS),0) >= 1
) T WHERE 1=1
AND T.BASIC_EMPT_CNT >= NVL(TO_NUMBER(#{startBasicEmptCnt}),0)
AND T.BASIC_EMPT_CNT < NVL(TO_NUMBER(#{endBasicEmptCnt}),0)+1

SELECT T.CONTRACT_NUM, T.SOC, T.SERVICE_NM, T.AGENT_ID, T.AGENT_NM, T.BASIC_REMAINS, T.BASIC_EXPIRE, T.BASIC_EMPT_DT, T.ENTER_DATE, T.STATUS_STOP_DT, T.SUB_STATUS, T.SUB_STATUS_NM, T.SUB_LINK_NAME, T.LST_COM_ACTV_DATE, T.AGENT_SALE_ID , T.AGENT_SALE_NM, T.MNP_IND_CD, T.MNP_IND_CD_NM, T.TOTAL_BASIC_CHG, T.PPS35_REUSE_DATE, T.AD_NATION, T.AD_NATION_NM, T.BASIC_EMPT_CNT, T.USE_TERM FROM ( SELECT
/*+ INDEX_DESC(A PPS_CUSTOMER_IDX1) ORDERED USE_NL(A B) */
/*+ INDEX_DESC(A PPS_CUSTOMER_IDX1) ORDERED USE_NL(A B) */
NVL(B.CONTRACT_NUM,'-') CONTRACT_NUM, NVL(A.SOC,'-') SOC, NVL((SELECT RATE_NM SERVICE_NM FROM MSP_RATE_MST WHERE RATE_CD = SOC and rownum = 1),'-') SERVICE_NM, NVL(AGENT_ID, '') AGENT_ID, NVL(F_GET_AGENT_NM(AGENT_ID),'-') AGENT_NM, NVL(BASIC_REMAINS,'0') BASIC_REMAINS, NVL(TO_CHAR(BASIC_EXPIRE, 'YYYY-MM-DD'),'-') BASIC_EXPIRE, NVL(TO_CHAR(BASIC_EMPT_DT, 'YYYY-MM-DD'),'-') BASIC_EMPT_DT, NVL(TO_CHAR(A.ENTER_DATE, 'YYYY-MM-DD HH24:MI:SS'),'-') ENTER_DATE, NVL(TO_CHAR(STATUS_STOP_DT, 'YYYY-MM-DD'),'-') STATUS_STOP_DT, NVL(B.SUB_STATUS,'-') SUB_STATUS, NVL(F_GET_KT_CODE_NM('PPS_CUSTOMER','SUB_STATUS',B.SUB_STATUS),'-') SUB_STATUS_NM, NVL(B.SUB_LINK_NAME,'-') SUB_LINK_NAME, NVL(B.LST_COM_ACTV_DATE,'-') LST_COM_ACTV_DATE, NVL(A.AGENT_SALE_ID,'-') AGENT_SALE_ID , NVL(F_GET_AGENT_NM(AGENT_SALE_ID),'-') AGENT_SALE_NM, NVL(MNP_IND_CD, '-') MNP_IND_CD, DECODE(MNP_IND_CD, '', '신규', '이동') MNP_IND_CD_NM, NVL(A.TOTAL_BASIC_CHG, '0') TOTAL_BASIC_CHG, DECODE(SUBSTR(LST_COM_ACTV_DATE, 7, 2), '29', '28', '30', '28', '31', '28', SUBSTR(LST_COM_ACTV_DATE, 7, 2)) AS PPS35_REUSE_DATE, NVL(AD_NATION,'') AS AD_NATION, DECODE(AD_NATION,'','미등록', F_GET_KT_CODE_NM('PPS_CUSTOMER', 'AD_NATION', AD_NATION)) AS AD_NATION_NM, CASE WHEN BASIC_EMPT_DT > LAST_BASIC_CHG_DT THEN TRUNC(SYSDATE) - TRUNC(BASIC_EMPT_DT) ELSE NULL END AS BASIC_EMPT_CNT, TO_NUMBER(DECODE(B.SUB_STATUS,'A', CEIL(SYSDATE - TO_DATE(B.LST_COM_ACTV_DATE, 'YYYY-MM-DD')),'S', CEIL(A.STATUS_STOP_DT - TO_DATE(B.LST_COM_ACTV_DATE, 'YYYY-MM-DD')),'C', CEIL(A.STATUS_CANCEL_DT - TO_DATE(B.LST_COM_ACTV_DATE, 'YYYY-MM-DD')), '')) AS USE_TERM FROM PPS_CUSTOMER A, MSP_JUO_SUB_INFO B WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND ENTER_DATE > TO_DATE('1900-01-01','YYYY-MM-DD') AND B.SUB_STATUS IN ('A','S') AND A.SOC IN (SELECT SOC FROM PPS_CODE_SERVICE_TOPUP WHERE KT_MODE <> 'TOPUP_REFILL' )
AND B.CONTRACT_NUM = (select F_GET_LIKE_CTN2_CONTRACT_NUM(#{searchNm}) from dual)
AND B.CONTRACT_NUM = #{searchNm}
AND B.SUB_LINK_NAME LIKE '%' || #{searchNm} || '%'
AND A.ENTER_DATE >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
AND A.ENTER_DATE < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND BASIC_EMPT_DT >= TO_DATE(#{startEmptDt}, 'YYYY-MM-DD')
AND BASIC_EMPT_DT < TO_DATE(#{endEmptDt}, 'YYYY-MM-DD')+1
AND A.SOC = #{searchFeatures}
AND B.SUB_STATUS = #{searchSubStatus}
AND NVL(TO_NUMBER(BASIC_REMAINS),0) = 0
AND NVL(TO_NUMBER(BASIC_REMAINS),0) >= 1
) T WHERE 1=1
AND T.BASIC_EMPT_CNT >= NVL(TO_NUMBER(#{startBasicEmptCnt}),0)
AND T.BASIC_EMPT_CNT < NVL(TO_NUMBER(#{endBasicEmptCnt}),0)+1

	{CALL P_CUSTOMER_STAY_EXPIR_DT(
						#{opCode, jdbcType=VARCHAR}
						, #{contractNum, jdbcType=VARCHAR}
						, #{stayExpirDt, jdbcType=VARCHAR}	
						, #{adminId, jdbcType=VARCHAR}						
						, #{oRetCd, mode=OUT, javaType=string, jdbcType=VARCHAR}
						, #{oRetMsg, mode=OUT, javaType=string, jdbcType=VARCHAR} 
						)
     }
